SELECT city 
FROM housing_data 
WHERE property_value = (SELECT MAX(property_value) FROM housing_data);

SELECT owner_name, MIN(year_built) as earliest_year_built
FROM housing_data
WHERE owner_name = 'John Doe';

SELECT SUM(property_value * crime_rate) / SUM(crime_rate) AS typical_worth
FROM housing_data
WHERE crime_rate > (SELECT AVG(crime_rate) FROM housing_data);

SELECT *
FROM housing_data
WHERE rental_price > (SELECT AVG(rental_price) FROM housing_data);

SELECT AVG(property_value)
FROM housing_data
WHERE property_type = 'Single-family';

SELECT *
FROM environmental_factors
WHERE air_quality_index < (SELECT AVG(air_quality_index) FROM environmental_factors);

SELECT h.owner_name, u.role
FROM housing_data h
INNER JOIN user_roles u ON h.owner_name = u.user_name;
